'use client';
import { motion, useMotionValue, useSpring } from 'framer-motion';
import { useRef } from 'react';
export default function MagneticCTA({ heading, subheading, cta }) {
  const ref = useRef(null);
  const x = useMotionValue(0);
  const y = useMotionValue(0);
  const sx = useSpring(x, { stiffness: 150, damping: 15 });
  const sy = useSpring(y, { stiffness: 150, damping: 15 });
  return (
    <section className='px-6 py-24 text-center'>
      <h2 className='text-4xl md:text-6xl font-semibold tracking-tighter max-w-3xl mx-auto'>{heading}</h2>
      {subheading && <p className='mt-4 text-[color:var(--muted)]'>{subheading}</p>}
      <motion.a ref={ref} href={cta?.href || '#'} style={{x:sx,y:sy}}
        onMouseMove={(e)=>{const r=ref.current.getBoundingClientRect();x.set((e.clientX-r.left-r.width/2)*0.4);y.set((e.clientY-r.top-r.height/2)*0.4);}}
        onMouseLeave={()=>{x.set(0);y.set(0);}}
        className='mt-10 inline-flex items-center gap-2 px-8 h-14 rounded-full bg-[color:var(--primary)] text-[color:var(--bg)] font-medium'>
        {cta?.label || 'Get started'} →
      </motion.a>
    </section>
  );
}

